<script>
function erError(m){$('.isi_warning_delete').text(m||'Employee Report gagal diproses.');$('.error_data_delete').fadeIn();}
function erFilters(){return{as_of_date:$('#filter_as_of_date').val(),employment_status:$('#filter_employment_status').val(),employee_group:$('#filter_employee_group').val(),work_location_type:$('#filter_work_location_type').val(),department_code:$('#filter_department_code').val(),job_title_id:$('#filter_job_title_id').val(),company_structure_id:$('#filter_company_structure_id').val(),manager_employee_id:$('#filter_manager_employee_id').val(),keyword:$('#filter_keyword').val()};}
function ajaxSel(s,act,ph){$(s).select2({width:'100%',allowClear:true,placeholder:ph,ajax:{url:'<?=base_admin();?>modul/employee_report/employee_report_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.er-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_employment_status,#filter_employee_group,#filter_work_location_type').select2({width:'100%',allowClear:true});ajaxSel('#filter_department_code','department_search','Semua Department');ajaxSel('#filter_job_title_id','job_title_search','Semua Job Title');ajaxSel('#filter_company_structure_id','org_search','Semua Org Unit');ajaxSel('#filter_manager_employee_id','employee_search','Semua Manager');}
var dt=$('#dtb_employee_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'72px',targets:1}],ajax:{url:'<?=base_admin();?>modul/employee_report/employee_report_data.php',type:'post',data:function(d){$.extend(d,erFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_probation').text(k.probation||0);$('#kpi_contract').text(k.contract||0);$('#kpi_operator').text(k.operator||0);$('#kpi_leader').text(k.leader||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);erError('Data Employee Report gagal dimuat.');}}});
$('#btn_filter_er').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_er').click(function(){$('#filter_as_of_date').val('<?=$asOf;?>');$('#filter_employment_status,#filter_employee_group,#filter_work_location_type,#filter_department_code,#filter_job_title_id,#filter_company_structure_id,#filter_manager_employee_id').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_er').click(function(){window.location='<?=base_admin();?>modul/employee_report/employee_report_action.php?act=export&'+$.param(erFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$(document).on('click','.btn-er-detail',function(){$.post('<?=base_admin();?>modul/employee_report/employee_report_action.php?act=detail',{id:$(this).data('id')},function(h){$('#er_detail_body').html(h);$('#modal_er_detail').modal('show');});});
});
</script>
